const r = $input.first().json;
const raw = r.choices?.[0]?.message?.content || '{}';
let parsed; try { parsed = JSON.parse(raw); } catch(e) { parsed = { diagnoses:[], reasoning:'parse_error', needs_reretrival:false }; }
const ctx = $('Format Context').first().json;
return [{ json: { initial: parsed, user_prompt_initial: ctx.user_prompt, evidence_ids: ctx.evidence_ids, docs: ctx.docs, case: ctx.case } }];

const r = $input.first().json;
const raw = r.choices?.[0]?.message?.content || '{}';
let parsed; try { parsed = JSON.parse(raw); } catch(e) { parsed = { diagnoses:[], reasoning:'parse_error', needs_reretrival:false }; }
const prev = $('Parse Diagnosis').first().json;
return [{ json: { initial: prev.initial, reflection: parsed, evidence_ids: prev.evidence_ids, case: prev.case } }];

const j = $input.first().json;
const uuidRe = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
const allowed = new Set(j.evidence_ids);
const filt = (lst) => (lst||[]).map(d => ({...d, evidence_ids: (d.evidence_ids||[]).filter(e => uuidRe.test(e) && allowed.has(e))}));
const final_diagnoses = filt(j.reflection.diagnoses);
return [{ json: {
  case_id: j.case.case_id || null,
  initial_diagnosis: filt(j.initial.diagnoses),
  reflection_diagnosis: final_diagnoses,
  final_diagnosis: final_diagnoses,
  retrieved_evidence_ids: j.evidence_ids,
  needs_reretrival: !!j.reflection.needs_reretrival,
  disclaimer: 'Not a medical diagnosis; consult a clinician.'
} }];
